   186→// assignJobToWorker assigns a job to a specific worker
   187→// This runs in a separate goroutine to avoid blocking the dispatcher
   188→func (d *Dispatcher) assignJobToWorker(ctx context.Context, worker *WorkerState, job *Job) {
   189→	// TODO: In real implementation, communicate with Julia via shared memory
   190→	// For now, simulate processing
   191→	defer func() {
   192→		worker.SetState("IDLE")
   193→		worker.IncrementProcessed()
   194→	}()
   195→
   196→	// Simulate work
   197→	time.Sleep(10 * time.Millisecond)
   198→
   199→	// Send dummy response
   200→	select {
   201→	case job.Response <- []byte("processed"):
   202→	case <-ctx.Done():
   203→	}
