    55→// Run executes the worker main loop (pinned to OS thread if cpuCore >= 0)
    56→func (w *Worker) Run(ctx context.Context, jobQueue chan *Job) error {
    57→	// Pin to OS thread if requested
    58→	if w.cpuCore >= 0 {
    59→		runtime.LockOSThread()
    60→		defer runtime.UnlockOSThread()
    61→
    62→		// TODO: Actually pin to CPU core using taskset
    63→		// cmd := exec.Command("taskset", "-p", "-c", fmt.Sprintf("%d", w.cpuCore), fmt.Sprintf("%d", os.Getpid()))
    64→		// cmd.Run()
    65→	}
    66→
    67→	for {
    68→		select {
    69→		case job := <-jobQueue:
    70→			if job == nil {
    71→				// Channel closed
    72→				return nil
    73→			}
    74→
    75→			result, err := w.processJob(ctx, job)
    76→			if err != nil {
    77→				atomic.AddUint64(&w.errors, 1)
    78→				w.lastError.Store(err)
    79→				job.Response <- nil
    80→			} else {
    81→				job.Response <- result
    82→			}
    83→
    84→			w.WorkerState.IncrementProcessed()
    85→
    86→		case <-ctx.Done():
    87→			return ctx.Err()
    88→		}
    89→	}
    90→}
