   166→// WorkerPool manages multiple workers
   167→type WorkerPool struct {
   168→	workers      []*Worker
   169→	jobQueues    []chan *Job
   170→	dispatcher   *Dispatcher
   171→	ctx          context.Context
   172→	cancel       context.CancelFunc
   173→	wg           sync.WaitGroup
   174→	totalStarted uint64 // atomic
   175→	totalStopped uint64 // atomic
   176→}
   177→
   178→// NewWorkerPool creates a new worker pool
   179→func NewWorkerPool(dispatcher *Dispatcher, workerCount int) (*WorkerPool, error) {
   180→	workers := make([]*Worker, workerCount)
   181→	jobQueues := make([]chan *Job, workerCount)
   182→
   183→	for i := 0; i < workerCount; i++ {
   184→		jobQueues[i] = make(chan *Job, 100) // Buffered job queue per worker
   185→		workers[i] = NewWorker(i, dispatcher.workers[i], i%8) // Pin to 8 cores
   186→	}
   187→
   188→	ctx, cancel := context.WithCancel(context.Background())
   189→
   190→	return &WorkerPool{
   191→		workers:    workers,
   192→		jobQueues:  jobQueues,
   193→		dispatcher: dispatcher,
   194→		ctx:        ctx,
   195→		cancel:     cancel,
   196→	}, nil
   197→}
   198→
   199→// Start launches all workers
   200→func (wp *WorkerPool) Start(ctx context.Context) error {
   201→	for i, worker := range wp.workers {
   202→		if err := worker.Start(ctx); err != nil {
   203→			return fmt.Errorf("failed to start worker %d: %w", i, err)
   204→		}
   205→
   206→		wp.wg.Add(1)
   207→		go func(w *Worker, idx int) {
   208→			defer wp.wg.Done()
   209→			atomic.AddUint64(&wp.totalStarted, 1)
   210→
   211→			if err := w.Run(ctx, wp.jobQueues[idx]); err != nil {
   212→				w.lastError.Store(err)
   213→			}
   214→
   215→			atomic.AddUint64(&wp.totalStopped, 1)
   216→		}(worker, i)
   217→	}
   218→
   219→	return nil
   220→}
   221→
   222→// Submit sends a job to a specific worker
   223→func (wp *WorkerPool) Submit(workerIdx int, job *Job) error {
   224→	if workerIdx < 0 || workerIdx >= len(wp.jobQueues) {
   225→		return fmt.Errorf("invalid worker index: %d", workerIdx)
   226→	}
   227→
   228→	select {
   229→	case wp.jobQueues[workerIdx] <- job:
   230→		return nil
   231→	case <-wp.ctx.Done():
   232→		return fmt.Errorf("worker pool shutting down")
   233→	default:
   234→		return fmt.Errorf("worker queue full")
   235→	}
   236→}
   237→
   238→// Stop gracefully shuts down all workers
   239→func (wp *WorkerPool) Stop() error {
   240→	wp.cancel()
   241→
   242→	// Close all job queues
   243→	for _, q := range wp.jobQueues {
   244→		close(q)
   245→	}
   246→
   247→	// Wait for all workers to finish
   248→	wp.wg.Wait()
   249→
   250→	// Close all workers
   251→	for _, w := range wp.workers {
   252→		if err := w.Close(); err != nil {
   253→			return err
   254→		}
   255→	}
   256→
   257→	return nil
   258→}
   259→
   260→// Stats returns stats for all workers
   261→func (wp *WorkerPool) Stats() []map[string]interface{} {
   262→	stats := make([]map[string]interface{}, len(wp.workers))
   263→	for i, w := range wp.workers {
   264→		stats[i] = w.GetStats()
   265→	}
   266→	return stats
   267→}
